/**
 * Attach live validation feedback to a form control.
 * @param {HTMLElement} field
 * @param {(value: string) => string | null} validator
 * @param {string} errorClass
 * @returns {() => void}
 */
export function attachFieldValidator(field, validator, errorClass = 'is-invalid') {
  const runValidation = () => {
    const value = 'value' in field ? String(field.value) : '';
    const message = validator(value);
    const isValid = message === null;
    field.classList.toggle(errorClass, !isValid);
    field.setAttribute('aria-invalid', isValid ? 'false' : 'true');
    return message;
  };

  const listener = () => runValidation();
  field.addEventListener('change', listener);
  runValidation();
  return () => field.removeEventListener('change', listener);
}
